import React from 'react'
import { useState } from 'react'

function Home() {
  let [counter, setCounter] = useState(0)

  const increament = () => {
    setCounter(counter + 1)
  }
  const decreament = () => {
    setCounter(counter - 1)
  }

  return (
    <>
      <h1>Home</h1>
    </>
  )
}

export default Home
